<?php

namespace Drupal\hudx_astro_forms___temp_astro_form_page\Controller;

use Drupal\Core\Controller\ControllerBase;
use Symfony\Component\HttpFoundation\JsonResponse;
use Symfony\Component\HttpFoundation\Request;

/**
 * REST-like API for form submissions — mirrors the local Express server.
 *
 * GET  /api/astro-forms---temp-astro-form-page/submissions  — returns all rows, newest first.
 * POST /api/astro-forms---temp-astro-form-page/submissions  — inserts a new row.
 *
 * Generated by 3PD module generator — do not edit manually.
 */
class SubmissionsController extends ControllerBase {

  public function list(): JsonResponse {
    $rows = \Drupal::database()
      ->select('hudx_astro_forms___temp_astro_form_page_submissions', 's')
      ->fields('s')
      ->orderBy('s.id', 'DESC')
      ->execute()
      ->fetchAll(\PDO::FETCH_ASSOC);

    return new JsonResponse(array_values($rows));
  }

  public function submit(Request $request): JsonResponse {
    $data = json_decode($request->getContent(), TRUE);

    if (empty($data['name']) || empty($data['message'])) {
      return new JsonResponse(['error' => 'name and message are required.'], 400);
    }

    \Drupal::database()
      ->insert('hudx_astro_forms___temp_astro_form_page_submissions')
      ->fields([
        'name'       => $data['name'],
        'message'    => $data['message'],
        'created_at' => date('Y-m-d H:i:s'),
      ])
      ->execute();

    return new JsonResponse(['status' => 'ok'], 201);
  }

}
